examples.query:
MATCH (person:Person)
WHERE EXISTS {
  MATCH (person)-[:KNOWS]->(:Person {city:'Berlin'})
}
RETURN person.name

MATCH (person:Person)
WHERE NOT EXISTS {
  MATCH (person)-[:KNOWS]->(:Person {city:'Vienna'})
}
RETURN person.name

CREATE CONSTRAINT person_name_unique IF NOT EXISTS
FOR (person:Person)
REQUIRE person.name IS UNIQUE;

CREATE INDEX room_type_index IF NOT EXISTS
FOR (room:Room)
ON (room.type);
